import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs.setdefault(name, {})[pkg['id']] = pkg.get('resolvedVersion', pkg.get('requestedVersion', ''))
    return pkgs

b = extract(base)
a = extract(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg,'—')
        av = a.get(proj,{}).get(pkg,'—')
        if bv != av:
            changes.append((proj, pkg, bv, av))
        else:
            unchanged.append((proj, pkg, bv))

print('=== CHANGES ===')
for c in changes: print(f'{c[0]:20} {c[1]:40} {c[2]:>10} -> {c[3]}')
if not changes: print('None')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages across all projects ===')
"

